define("mod_videoassessment/live_grade_total",[],(function(){function calculate(criteria,selected){var total=0;var max=0;Object.keys(criteria).forEach(function(critId){var levels=criteria[critId];var maxForCrit=levels.length===0?0:Math.max.apply(null,levels);max+=maxForCrit;if(Object.prototype.hasOwnProperty.call(selected,critId)){total+=selected[critId];}});var pct=max>0?Math.round((total/max)*100):0;return{total:total,max:max,percentage:pct};}function format(result){if(!result.max||result.max<=0){return"-";}return result.total+" / "+result.max+" ("+result.percentage+"%)";}function readSelection(root){var criteria={};var selected={};var critEls=root.querySelectorAll(".criterion");critEls.forEach(function(critEl,idx){var critId=critEl.id||("criterion-"+idx);var levelEls=critEl.querySelectorAll(".level");criteria[critId]=[];levelEls.forEach(function(lvl){var score=parseFloat(lvl.dataset.score);if(!isNaN(score)){criteria[critId].push(score);if(lvl.classList.contains("checked")){selected[critId]=score;}}});});return{criteria:criteria,selected:selected};}function init(){var displays=document.querySelectorAll("[data-vassmt-live-grade]");displays.forEach(function(display){var rootSelector=display.dataset.vassmtRubricRoot||".gradingform_rubric";var root=document.querySelector(rootSelector);if(!root){return;}function refresh(){var snapshot=readSelection(root);var result=calculate(snapshot.criteria,snapshot.selected);display.textContent=format(result);}root.addEventListener("click",function(){window.setTimeout(refresh,50);});refresh();});}return{init:init,calculate:calculate,format:format};}));

